function Card({ children }) {
  return (
    <div className="border rounded-lg p-4 shadow">
      {children}
    </div>
  );
}

// Tudo entre <Card> e </Card> vira children:
<Card>
  <h2>Título do card</h2>
  <p>Qualquer conteúdo aqui dentro.</p>
  <button>Ação</button>
</Card>

// ❌ Sem children: API inflexível
<Card titulo="Olá" descricao="Mundo" botaoTexto="Clique" />

// ✅ Com children: composição flexível
<Card>
  <h2>Olá</h2>
  <p>Mundo</p>
  <button>Clique</button>
  <img src="foto.jpg" />  {/* Fácil adicionar qualquer coisa! */}
</Card>

