challenge.solution:
function AlertBox({ children, type }) {
  const colors = {
    success: 'green',
    error: 'red',
    info: 'blue',
  };
  return (
    <div style={{ border: `2px solid ${colors[type]}`, padding: 16, margin: 8, borderRadius: 8 }}>
      {children}
    </div>
  );
}

export default function App() {
  return (
    <div>
      <AlertBox type="success">
        <h3>Sucesso!</h3>
        <p>Operação concluída.</p>
      </AlertBox>
      <AlertBox type="error">
        <p>Algo deu errado. Tente novamente.</p>
      </AlertBox>
      <AlertBox type="info">
        <p>Dica: use children para conteúdo flexível!</p>
      </AlertBox>
    </div>
  );
}
